# Create multiple balls in a loop
for i in range(10):
    ball = it.ball.create(rad=0.1, pos=(i * 0.5, 0, 0))

import itasca as it

ball = it.ball.find(1)
if ball:
    print(ball.pos())
else:
    print('Ball not found')

ball = it.ball.find(1)
if ball:
    ball.delete()

# Delete balls below Z threshold
for ball in list(it.ball.list()):
    if ball.pos()[2] < -10:
        ball.delete()
